{
    "eventId": 1,
    "type": "REGISTRATION",
    "schema": {
        "title": "Spring Gala Registration Form",
        "description": "Sign up for the annual gala",
        "fields": [
            {
                "name": "fullName",
                "label": "Full Name",
                "type": "text",
                "required": true
            },
            {
                "name": "dietaryRestrictions",
                "label": "Dietary Restrictions",
                "type": "select",
                "options": ["None", "Vegetarian", "Vegan", "Gluten-Free"],
                "required": false
            }
        ]
    }
}

{
    "eventId": 1,
    "type": "FEEDBACK",
    "schema": {
        "title": "Spring Gala Feedback Form",
        "description": "Tell us your experience",
        "fields": [
            {
                "name": "rating",
                "label": "Overall Rating (1-5)",
                "type": "number",
                "required": true
            },
            {
                "name": "comments",
                "label": "Additional Comments",
                "type": "textarea",
                "required": false
            }
        ]
    }
}
